import type { CareerQuestion } from "./rrt-questions";

export const psychotherapistQuestionsBatch5: CareerQuestion[] = [
  { id: "rp-751", stem: "A client begins treating the therapist as if they were their critical mother, frequently seeking approval and becoming anxious when the therapist is neutral. This is an example of:", options: ["Positive transference with maternal qualities","Countertransference","Projective identification","Reaction formation"], correctIndex: 0, rationale: "Transference involves the client unconsciously redirecting feelings about significant figures onto the therapist. Here, the client is transferring the dynamic with their critical mother, seeking approval as they would from her.", difficulty: 2, category: "Psychodynamic Therapy", topic: "Transference" },
  { id: "rp-752", stem: "In psychoanalytic theory, the defense mechanism where an individual attributes their own unacceptable thoughts to another person is called:", options: ["Projection","Displacement","Rationalization","Sublimation"], correctIndex: 0, rationale: "Projection involves attributing one's own unacceptable impulses, thoughts, or feelings to another person. It reduces anxiety by allowing the individual to deal with the threatening material externally.", difficulty: 1, category: "Psychodynamic Therapy", topic: "Defense Mechanisms" },
  { id: "rp-753", stem: "A therapist notices they feel unusually protective of a young client and begins offering advice beyond the therapeutic frame. This likely reflects:", options: ["Countertransference stemming from the therapist's own parental instincts","Appropriate clinical flexibility","The client's projective identification","A corrective emotional experience"], correctIndex: 0, rationale: "Countertransference occurs when the therapist's own unresolved feelings are activated by the client. Over-protectiveness and boundary softening suggest the therapist is responding to personal needs rather than clinical ones.", difficulty: 3, category: "Psychodynamic Therapy", topic: "Countertransference" },
  { id: "rp-754", stem: "According to Melanie Klein, the 'paranoid-schizoid position' in infancy is characterized by:", options: ["Splitting objects into entirely good or entirely bad","Integration of good and bad aspects of the object","Oedipal rivalry with the same-sex parent","Secure attachment to the primary caregiver"], correctIndex: 0, rationale: "Klein's paranoid-schizoid position describes early infancy where the infant uses splitting to manage anxiety, perceiving the breast/mother as either all-good (gratifying) or all-bad (frustrating) without integration.", difficulty: 4, category: "Psychodynamic Therapy", topic: "Object Relations" },
  { id: "rp-755", stem: "Winnicott's concept of the 'good enough mother' suggests that optimal development requires:", options: ["A caregiver who provides adequate but not perfect attunement, allowing graduated frustration","Perfect mirroring of the infant's needs at all times","Strict discipline and consistent routines from birth","Minimal physical contact to promote independence"], correctIndex: 0, rationale: "Winnicott argued that perfect attunement is neither possible nor desirable. The 'good enough mother' provides sufficient holding and gradually fails in manageable ways, promoting the infant's capacity for self-regulation.", difficulty: 3, category: "Psychodynamic Therapy", topic: "Object Relations" },
  { id: "rp-756", stem: "In Bowlby's attachment theory, a child who shows distress upon separation but is easily comforted upon reunion displays:", options: ["Secure attachment","Anxious-ambivalent attachment","Avoidant attachment","Disorganized attachment"], correctIndex: 0, rationale: "Secure attachment is characterized by appropriate distress upon separation and rapid comfort upon reunion. The child uses the caregiver as a secure base for exploration and shows clear preference for the caregiver over strangers.", difficulty: 1, category: "Psychodynamic Therapy", topic: "Attachment Theory" },
  { id: "rp-757", stem: "Freud's structural model of the psyche includes:", options: ["Id, ego, and superego","Conscious, preconscious, and unconscious","Oral, anal, and phallic stages","Eros, thanatos, and libido"], correctIndex: 0, rationale: "Freud's structural model divides the psyche into id (primitive drives), ego (reality-mediating executive), and superego (internalized moral standards). These structures interact dynamically to produce behavior.", difficulty: 1, category: "Psychodynamic Therapy", topic: "Psychoanalytic Concepts" },
  { id: "rp-758", stem: "A client who was physically abused as a child now unconsciously provokes the therapist into angry responses. This process is best understood as:", options: ["Projective identification","Simple projection","Intellectualization","Denial"], correctIndex: 0, rationale: "Projective identification involves projecting unacceptable aspects of self into another and then interacting in ways that pressure the other person to experience and enact those projected feelings. The client recreates the abusive dynamic.", difficulty: 4, category: "Psychodynamic Therapy", topic: "Defense Mechanisms" },
  { id: "rp-759", stem: "The concept of 'free association' in psychoanalysis requires the patient to:", options: ["Report whatever comes to mind without censoring or editing","Focus exclusively on childhood memories","Describe dreams in sequential order","Respond to specific prompts given by the analyst"], correctIndex: 0, rationale: "Free association is the fundamental rule of psychoanalysis where the patient verbalizes all thoughts, feelings, and images without censorship. This allows unconscious material to emerge through the pattern of associations.", difficulty: 1, category: "Psychodynamic Therapy", topic: "Psychoanalytic Concepts" },
  { id: "rp-760", stem: "According to Kohut's self psychology, 'mirroring' refers to:", options: ["The caregiver's empathic reflection of the child's sense of greatness and value","The child's imitation of parental behavior","The therapist repeating the client's words back verbatim","The client seeing themselves reflected in other group members"], correctIndex: 0, rationale: "Kohut described mirroring as a selfobject function where the caregiver reflects back the child's grandiosity with empathic admiration, helping the child develop healthy self-esteem and a cohesive sense of self.", difficulty: 3, category: "Psychodynamic Therapy", topic: "Object Relations" },
  { id: "rp-761", stem: "A man who harbors unconscious aggressive impulses toward his boss instead becomes excessively submissive and agreeable. This defense mechanism is:", options: ["Reaction formation","Sublimation","Displacement","Undoing"], correctIndex: 0, rationale: "Reaction formation involves transforming an unacceptable impulse into its opposite. The unconscious aggression is converted into exaggerated submissiveness, keeping the threatening feelings out of awareness.", difficulty: 2, category: "Psychodynamic Therapy", topic: "Defense Mechanisms" },
  { id: "rp-762", stem: "In object relations theory, 'transitional objects' (Winnicott) serve the developmental function of:", options: ["Bridging the gap between the infant's internal world and external reality","Replacing the need for the primary caregiver","Stimulating cognitive development through play","Serving as a reward for good behavior"], correctIndex: 0, rationale: "Transitional objects (e.g., blankets, stuffed animals) occupy an intermediate area between subjective internal reality and objective external reality, helping the child negotiate the separation-individuation process.", difficulty: 3, category: "Psychodynamic Therapy", topic: "Object Relations" },
  { id: "rp-763", stem: "A client who was emotionally neglected in childhood forms an intense, idealized attachment to the therapist and panics at any sign of the therapist's unavailability. This attachment pattern is:", options: ["Anxious-preoccupied attachment","Dismissive-avoidant attachment","Secure attachment","Fearful-avoidant attachment"], correctIndex: 0, rationale: "Anxious-preoccupied attachment in adults is characterized by intense desire for closeness, preoccupation with the attachment figure, hypervigilance to rejection cues, and difficulty tolerating separation.", difficulty: 3, category: "Psychodynamic Therapy", topic: "Attachment Theory" },
  { id: "rp-764", stem: "Freud's concept of 'overdetermination' in dream analysis means that:", options: ["A single dream element can represent multiple unconscious meanings simultaneously","Dreams have only one correct interpretation","The manifest content is always more important than latent content","Dreams are random and carry no psychological significance"], correctIndex: 0, rationale: "Overdetermination means that every dream element is determined by multiple unconscious sources and can carry several meanings. This reflects the condensation process in dream work where multiple ideas merge into one image.", difficulty: 4, category: "Psychodynamic Therapy", topic: "Psychoanalytic Concepts" },
  { id: "rp-765", stem: "The defense mechanism of 'intellectualization' is characterized by:", options: ["Using abstract thinking and generalization to distance oneself from emotional content","Unconsciously forgetting traumatic events","Reverting to earlier developmental behaviors","Channeling unacceptable impulses into socially acceptable activities"], correctIndex: 0, rationale: "Intellectualization involves excessive use of abstract thinking to avoid the emotional impact of a situation. The person discusses feelings in detached, theoretical terms rather than experiencing them directly.", difficulty: 2, category: "Psychodynamic Therapy", topic: "Defense Mechanisms" },
  { id: "rp-766", stem: "Margaret Mahler's separation-individuation theory describes which critical developmental phase occurring between 5 and 36 months?", options: ["The child's gradual psychological differentiation from the mother","The resolution of the Oedipus complex","The development of formal operational thinking","The formation of peer relationships"], correctIndex: 0, rationale: "Mahler's separation-individuation process describes how the infant moves from symbiotic fusion with the mother through differentiation, practicing, rapprochement, and object constancy phases to achieve psychological separateness.", difficulty: 4, category: "Psychodynamic Therapy", topic: "Object Relations" },
  { id: "rp-767", stem: "A therapist working psychodynamically notices that the client consistently arrives late to sessions following interpretations about anger. This pattern is best understood as:", options: ["Resistance manifesting through enactment","A scheduling conflict","Passive-aggressive personality disorder","Lack of motivation for treatment"], correctIndex: 0, rationale: "Resistance in psychodynamic therapy often manifests behaviorally. The temporal connection between interpretations about anger and lateness suggests the client is unconsciously avoiding the anxiety generated by emerging awareness of hostile feelings.", difficulty: 3, category: "Psychodynamic Therapy", topic: "Psychoanalytic Concepts" },
  { id: "rp-768", stem: "In Fairbairn's object relations theory, psychopathology is understood primarily as:", options: ["Resulting from disturbances in early relationships with significant objects","A conflict between id impulses and superego demands","A failure in cognitive development","The result of inadequate behavioral reinforcement"], correctIndex: 0, rationale: "Fairbairn shifted psychoanalytic theory from drive theory to relational theory, proposing that libido is object-seeking (not pleasure-seeking) and that psychopathology stems from disturbed early relationships with primary objects.", difficulty: 5, category: "Psychodynamic Therapy", topic: "Object Relations" },
  { id: "rp-769", stem: "A client describes feeling nothing when recounting a traumatic car accident. The defense mechanism most likely operating is:", options: ["Isolation of affect","Repression","Denial","Dissociation"], correctIndex: 0, rationale: "Isolation of affect separates the emotional component from the intellectual awareness of an event. The client can describe the trauma factually but is disconnected from the associated feelings.", difficulty: 3, category: "Psychodynamic Therapy", topic: "Defense Mechanisms" },
  { id: "rp-770", stem: "According to attachment theory, the 'internal working model' refers to:", options: ["Mental representations of self and others formed through early attachment experiences","The therapist's conceptualization of the client's problems","A cognitive-behavioral treatment planning framework","A neurological model of brain development"], correctIndex: 0, rationale: "Internal working models are cognitive-affective schemas about the self, others, and relationships formed from early attachment experiences. They guide expectations and behavior in subsequent relationships throughout life.", difficulty: 2, category: "Psychodynamic Therapy", topic: "Attachment Theory" },
  { id: "rp-771", stem: "The psychoanalytic concept of 'working through' refers to:", options: ["The repeated examination of unconscious conflicts and resistances until insight leads to lasting change","Completing homework assignments between sessions","The initial phase of establishing rapport","Terminating therapy after symptom resolution"], correctIndex: 0, rationale: "Working through is the gradual process of repeatedly confronting repressed material and resistances in different contexts until the patient achieves genuine emotional insight and lasting characterological change.", difficulty: 3, category: "Psychodynamic Therapy", topic: "Psychoanalytic Concepts" },
  { id: "rp-772", stem: "A woman who was abandoned by her father in childhood consistently chooses emotionally unavailable partners. From an object relations perspective, this reflects:", options: ["Repetition compulsion driven by internalized object relations","Conscious partner selection based on preferences","A healthy attachment strategy","Random relationship patterns"], correctIndex: 0, rationale: "Repetition compulsion involves unconsciously recreating early relational patterns. The internalized representation of the unavailable father-object becomes the template for partner selection, driven by the wish to master the original trauma.", difficulty: 3, category: "Psychodynamic Therapy", topic: "Object Relations" },
  { id: "rp-773", stem: "In the Strange Situation procedure (Ainsworth), a child classified as 'avoidant' typically:", options: ["Shows minimal distress at separation and ignores or avoids the caregiver upon reunion","Clings to the caregiver and refuses to explore the room","Exhibits contradictory approach-avoidance behaviors","Explores freely and is easily comforted after brief distress"], correctIndex: 0, rationale: "Avoidant attachment (Type A) is characterized by apparent indifference to separation and active avoidance of the caregiver upon reunion. These children have learned to suppress attachment behaviors due to consistently unresponsive caregiving.", difficulty: 2, category: "Psychodynamic Therapy", topic: "Attachment Theory" },
  { id: "rp-774", stem: "The defense mechanism of 'sublimation' is considered mature because it:", options: ["Channels unacceptable impulses into socially valued activities","Completely eliminates the original impulse","Prevents the person from ever experiencing negative emotions","Requires no psychological energy to maintain"], correctIndex: 0, rationale: "Sublimation transforms socially unacceptable impulses (aggression, sexuality) into constructive outlets (art, sports, work). It is considered the healthiest defense because it allows partial gratification while serving social adaptation.", difficulty: 1, category: "Psychodynamic Therapy", topic: "Defense Mechanisms" },
  { id: "rp-775", stem: "A client in psychodynamic therapy begins having dreams about locked doors and hidden rooms. The therapist interprets these as potentially reflecting:", options: ["Unconscious material that is being kept from awareness","The client's interest in real estate","Random neural firing without psychological meaning","The client's fear of physical spaces"], correctIndex: 0, rationale: "In psychodynamic dream interpretation, locked doors and hidden rooms commonly symbolize repressed unconscious material, secrets, or aspects of self that are being kept from awareness. The therapist explores these as potential pathways to unconscious content.", difficulty: 2, category: "Psychodynamic Therapy", topic: "Psychoanalytic Concepts" },
  { id: "rp-776", stem: "Kernberg's conceptualization of borderline personality organization emphasizes:", options: ["Identity diffusion, primitive defenses, and intact reality testing under stress","Strong ego boundaries and mature defense mechanisms","Psychotic-level fragmentation without recovery","Complete absence of object relations"], correctIndex: 0, rationale: "Kernberg describes borderline personality organization as characterized by identity diffusion, reliance on primitive defenses (splitting, projective identification), and reality testing that is generally intact but may falter under stress.", difficulty: 4, category: "Psychodynamic Therapy", topic: "Object Relations" },
  { id: "rp-777", stem: "A client who was raised by an alcoholic parent and learned to suppress their own needs to manage the parent's emotions likely developed which pattern?", options: ["A false self organization (Winnicott)","A secure attachment pattern","Healthy individuation","Optimal self-regulation"], correctIndex: 0, rationale: "Winnicott's false self develops when the child must comply with environmental demands rather than express authentic needs. The child creates a compliant, caretaking facade while the true self remains hidden and undeveloped.", difficulty: 3, category: "Psychodynamic Therapy", topic: "Object Relations" },
  { id: "rp-778", stem: "The concept of 'mentalization' in psychodynamic therapy refers to:", options: ["The capacity to understand behavior in terms of underlying mental states such as thoughts, feelings, and intentions","The process of memorizing therapeutic concepts","The ability to intellectualize emotional experiences","A meditation technique used in therapy"], correctIndex: 0, rationale: "Mentalization (Fonagy) is the capacity to perceive and interpret human behavior in terms of intentional mental states. Deficits in mentalization are associated with personality disorders and insecure attachment.", difficulty: 3, category: "Psychodynamic Therapy", topic: "Psychoanalytic Concepts" },
  { id: "rp-779", stem: "A client who regularly 'forgets' to pay their therapy bill may be exhibiting which type of resistance?", options: ["Acting out resistance through unconscious symbolic communication","A simple financial difficulty","Conscious manipulation of the therapist","Psychotic disorganization"], correctIndex: 0, rationale: "In psychodynamic therapy, 'forgetting' to pay can be understood as a form of resistance communicated through action rather than words. It may express unconscious ambivalence about treatment, hostility toward the therapist, or anxiety about dependency.", difficulty: 3, category: "Psychodynamic Therapy", topic: "Transference" },
  { id: "rp-780", stem: "According to Erikson's psychosocial development theory, the primary conflict during adolescence is:", options: ["Identity vs. role confusion","Industry vs. inferiority","Intimacy vs. isolation","Generativity vs. stagnation"], correctIndex: 0, rationale: "Erikson identified identity vs. role confusion as the central conflict of adolescence (12-18 years). Successful resolution results in a coherent sense of self; failure leads to identity confusion and difficulty committing to roles and values.", difficulty: 1, category: "Psychodynamic Therapy", topic: "Psychoanalytic Concepts" },
  { id: "rp-781", stem: "A therapist feels an intense urge to rescue a client from their abusive relationship, even considering offering their personal phone number. Supervision reveals this likely represents:", options: ["Countertransference reactivating the therapist's own history of witnessing domestic violence","Appropriate clinical concern for client safety","Evidence of the client's manipulative behavior","A necessary therapeutic boundary extension"], correctIndex: 0, rationale: "The intensity and boundary-crossing nature of the rescue impulse suggests countertransference. The therapist's own unresolved experiences are being activated, leading to reactions that go beyond appropriate clinical care.", difficulty: 4, category: "Psychodynamic Therapy", topic: "Countertransference" },
  { id: "rp-782", stem: "In psychoanalytic theory, 'secondary gain' refers to:", options: ["External benefits received from having symptoms, such as attention or avoidance of responsibilities","The primary psychological function of the symptom","The therapist's benefit from treating the patient","The secondary effects of medication"], correctIndex: 0, rationale: "Secondary gain refers to interpersonal or environmental advantages obtained from being symptomatic (attention, avoidance of work, financial compensation). Unlike primary gain (anxiety reduction), secondary gain involves external reinforcement of symptoms.", difficulty: 2, category: "Psychodynamic Therapy", topic: "Psychoanalytic Concepts" },
  { id: "rp-783", stem: "A client with disorganized attachment in childhood is most likely to display which pattern in the therapeutic relationship?", options: ["Simultaneous approach and avoidance behaviors with the therapist, oscillating between neediness and hostility","Consistent and stable engagement with the therapist","Polite but emotionally distant interactions","Complete absence of attachment behavior"], correctIndex: 0, rationale: "Disorganized attachment results from caregivers who are simultaneously the source of comfort and fear. In therapy, this manifests as contradictory behaviors - seeking closeness while also fearing it, creating an incoherent relational pattern.", difficulty: 4, category: "Psychodynamic Therapy", topic: "Attachment Theory" },
  { id: "rp-784", stem: "The defense mechanism of 'undoing' involves:", options: ["Performing an act designed to symbolically negate or atone for an unacceptable thought or action","Channeling impulses into creative activities","Reverting to an earlier developmental stage","Attributing one's own feelings to others"], correctIndex: 0, rationale: "Undoing is a defense mechanism where the individual attempts to reverse or neutralize a forbidden thought, feeling, or action through a compensatory behavior. It is commonly seen in OCD (e.g., ritual behaviors to 'undo' bad thoughts).", difficulty: 2, category: "Psychodynamic Therapy", topic: "Defense Mechanisms" },
  { id: "rp-785", stem: "Bion's concept of 'containment' in the therapeutic relationship refers to:", options: ["The therapist's capacity to receive, process, and return the client's overwhelming emotional states in a tolerable form","Setting rigid boundaries that prevent emotional expression","Physically restraining agitated clients","Limiting the topics discussed in therapy"], correctIndex: 0, rationale: "Bion described containment as the process where the therapist (like the mother) receives the client's projected raw emotional experiences (beta elements), metabolizes them, and returns them in a digestible form (alpha elements).", difficulty: 4, category: "Psychodynamic Therapy", topic: "Object Relations" },
  { id: "rp-786", stem: "A client who converts psychological distress into physical symptoms such as paralysis without neurological cause is using:", options: ["Conversion (somatization as a defense)","Sublimation","Rationalization","Identification"], correctIndex: 0, rationale: "Conversion involves transforming psychological conflict into somatic symptoms that symbolically represent the repressed wish or conflict. The physical symptom serves as a compromise formation, keeping the conflict unconscious.", difficulty: 2, category: "Psychodynamic Therapy", topic: "Defense Mechanisms" },
  { id: "rp-787", stem: "In psychodynamic therapy, the 'corrective emotional experience' (Alexander) refers to:", options: ["The therapist providing a relational experience that differs from the client's pathogenic early relationships","Correcting the client's cognitive distortions","Using behavioral techniques to modify emotions","Prescribing medication to correct chemical imbalances"], correctIndex: 0, rationale: "Alexander proposed that therapeutic change occurs when the therapist provides a new relational experience that contradicts the client's expectations based on early pathogenic relationships, allowing re-examination of old patterns.", difficulty: 3, category: "Psychodynamic Therapy", topic: "Psychoanalytic Concepts" },
  { id: "rp-788", stem: "A client with narcissistic personality disorder frequently idealizes the therapist one session and then devalues them the next. This pattern reflects:", options: ["Splitting as a primitive defense mechanism","Rational evaluation of the therapist's performance","Healthy ambivalence about therapy","Accurate perception of therapist inconsistency"], correctIndex: 0, rationale: "Splitting involves dividing objects into all-good or all-bad without integration. In narcissistic pathology, the therapist is idealized when meeting narcissistic needs and devalued when frustrating them, reflecting an inability to hold ambivalent representations.", difficulty: 3, category: "Psychodynamic Therapy", topic: "Defense Mechanisms" },
  { id: "rp-789", stem: "The concept of 'holding environment' (Winnicott) in therapy refers to:", options: ["Creating a safe, reliable therapeutic space that mirrors adequate maternal care","The physical arrangement of the therapy room","Restraining clients during emotional outbursts","Maintaining strict neutrality at all times"], correctIndex: 0, rationale: "Winnicott's holding environment in therapy involves providing consistent, empathic, non-retaliatory presence that mirrors adequate early caregiving. It allows the client to experience dependency and regression in a safe context.", difficulty: 2, category: "Psychodynamic Therapy", topic: "Object Relations" },
  { id: "rp-790", stem: "A client in analysis reports a dream where they are swimming in a vast ocean alone. The analyst might explore this as potentially representing:", options: ["Feelings of being overwhelmed or fears related to merging and separation","A literal desire to take up swimming as exercise","Evidence of a water phobia","Random imagery with no clinical significance"], correctIndex: 0, rationale: "In psychodynamic dream interpretation, being alone in a vast ocean can symbolize feelings of being overwhelmed by unconscious material, fears about engulfment or abandonment, and themes of separation-individuation.", difficulty: 3, category: "Psychodynamic Therapy", topic: "Psychoanalytic Concepts" },
  { id: "rp-791", stem: "Fonagy's concept of 'alien self' develops when:", options: ["The caregiver's mirroring is inaccurate or contingent on their own emotional state rather than the child's","The child receives too much positive attention","The child develops precocious cognitive abilities","The child has a genetic predisposition to personality disorder"], correctIndex: 0, rationale: "The alien self develops when the caregiver's mirroring is non-contingent - reflecting the caregiver's state rather than the child's. The child internalizes a representation that feels foreign, contributing to identity disturbance and emotional dysregulation.", difficulty: 5, category: "Psychodynamic Therapy", topic: "Attachment Theory" },
  { id: "rp-792", stem: "A client redirects anger meant for their spouse toward a less threatening target, such as a coworker. This defense mechanism is:", options: ["Displacement","Projection","Sublimation","Regression"], correctIndex: 0, rationale: "Displacement redirects emotional feelings (especially hostility) from the original object to a substitute target perceived as less threatening. The emotion is expressed but toward a safer recipient.", difficulty: 1, category: "Psychodynamic Therapy", topic: "Defense Mechanisms" },
  { id: "rp-793", stem: "In Lacanian psychoanalysis, the 'mirror stage' describes:", options: ["The infant's recognition of their reflection as a unified image, forming the basis of the ego","The therapist's technique of reflecting client statements","A stage in group therapy where members reflect each other","The development of empathy in early childhood"], correctIndex: 0, rationale: "Lacan's mirror stage (6-18 months) describes when the infant identifies with their specular image, creating an imaginary sense of wholeness and mastery that contrasts with their actual fragmented bodily experience, forming the foundation of the ego.", difficulty: 5, category: "Psychodynamic Therapy", topic: "Psychoanalytic Concepts" },
  { id: "rp-794", stem: "A client who experienced early maternal deprivation shows an inability to trust the therapist's reliability despite consistent behavior. From an attachment perspective, this reflects:", options: ["An insecure internal working model where others are expected to be unreliable","A rational assessment of the therapeutic relationship","Antisocial personality traits","The therapist's failure to establish rapport"], correctIndex: 0, rationale: "Early deprivation creates internal working models where attachment figures are experienced as unreliable and the self as unworthy of care. These models persist into adulthood and shape therapeutic expectations despite contrary evidence.", difficulty: 3, category: "Psychodynamic Therapy", topic: "Attachment Theory" },
  { id: "rp-795", stem: "The psychoanalytic concept of 'compromise formation' refers to:", options: ["A symptom that simultaneously expresses a forbidden wish and the defense against it","An agreement between therapist and client about treatment goals","A negotiation strategy used in couples therapy","The integration of different therapeutic approaches"], correctIndex: 0, rationale: "Compromise formation is a core psychoanalytic concept where symptoms, dreams, and parapraxes represent a compromise between the repressed wish (id), the defense (ego), and the prohibition (superego), allowing partial expression of each.", difficulty: 4, category: "Psychodynamic Therapy", topic: "Psychoanalytic Concepts" },
  { id: "rp-796", stem: "A child in Bowlby's attachment theory who shows extreme distress during separation and is inconsolable upon reunion, oscillating between clinging and angry resistance, demonstrates:", options: ["Anxious-ambivalent (resistant) attachment","Secure attachment","Avoidant attachment","Disorganized attachment"], correctIndex: 0, rationale: "Anxious-ambivalent (Type C) attachment features extreme separation distress and ambivalent reunion behavior - the child simultaneously seeks and resists contact, reflecting inconsistent caregiving that makes the child uncertain about caregiver availability.", difficulty: 2, category: "Psychodynamic Therapy", topic: "Attachment Theory" },
  { id: "rp-797", stem: "In psychodynamic therapy, 'negative transference' involves:", options: ["The client directing hostile, angry, or distrustful feelings toward the therapist based on past relationships","The therapist's negative feelings about the client","The client's realistic complaints about the therapy","Poor therapeutic outcomes"], correctIndex: 0, rationale: "Negative transference occurs when the client displaces hostile, mistrustful, or contemptuous feelings from past significant figures onto the therapist. Working through negative transference is crucial for psychodynamic treatment.", difficulty: 2, category: "Psychodynamic Therapy", topic: "Transference" },
  { id: "rp-798", stem: "Ogden's concept of the 'analytic third' refers to:", options: ["A co-created intersubjective experience that belongs neither to analyst nor patient alone","A third person present in the therapy room","The use of triangulation in treatment","The superego's role in the therapeutic process"], correctIndex: 0, rationale: "Ogden described the analytic third as the intersubjective experience generated between analyst and analysand that has its own quality and exists at the intersection of both subjectivities. It is co-constructed and cannot be reduced to either participant.", difficulty: 5, category: "Psychodynamic Therapy", topic: "Psychoanalytic Concepts" },
  { id: "rp-799", stem: "A client explains their partner's infidelity by saying 'it must have been because they were under a lot of stress at work.' This defense mechanism is:", options: ["Rationalization","Denial","Projection","Displacement"], correctIndex: 0, rationale: "Rationalization involves creating logical, socially acceptable explanations for behavior that is emotionally painful. It protects against the full emotional impact of the partner's betrayal by providing a reasonable cause.", difficulty: 1, category: "Psychodynamic Therapy", topic: "Defense Mechanisms" },
  { id: "rp-800", stem: "The concept of 'transference neurosis' in classical psychoanalysis refers to:", options: ["The organization of the patient's transference reactions into a coherent pattern that recapitulates their infantile neurosis within the analytic relationship","A mental disorder caused by the therapeutic process","The therapist developing neurotic symptoms","A brief psychotic episode during treatment"], correctIndex: 0, rationale: "Transference neurosis describes the crystallization of the patient's core neurotic conflicts within the analytic relationship, allowing direct observation and interpretation of the infantile neurosis as it unfolds in real-time.", difficulty: 5, category: "Psychodynamic Therapy", topic: "Transference" },
  { id: "rp-801", stem: "An adult who returns to thumb-sucking during periods of extreme stress is demonstrating:", options: ["Regression","Fixation","Sublimation","Repression"], correctIndex: 0, rationale: "Regression involves retreating to an earlier developmental stage when confronted with overwhelming anxiety. Thumb-sucking in an adult represents a return to oral-stage comfort behaviors used in infancy.", difficulty: 1, category: "Psychodynamic Therapy", topic: "Defense Mechanisms" },
  { id: "rp-802", stem: "Stern's concept of 'attunement' in infant development describes:", options: ["The caregiver's cross-modal matching of the infant's affective states","The infant's ability to imitate facial expressions","The development of language comprehension","The child's capacity for self-regulation"], correctIndex: 0, rationale: "Stern's affect attunement involves the caregiver responding to the infant's emotional state through a different sensory modality (e.g., matching vocal rhythm to the infant's movement), communicating shared feeling states.", difficulty: 4, category: "Psychodynamic Therapy", topic: "Attachment Theory" },
  { id: "rp-803", stem: "A psychodynamic therapist notices they consistently forget the appointment times of a particular client. This likely represents:", options: ["Countertransference manifesting as an enactment","Simple scheduling difficulties","The client's projective identification causing therapist confusion","Evidence of therapist burnout across all clients"], correctIndex: 0, rationale: "Selectively forgetting one client's appointments suggests countertransference. The therapist may be unconsciously avoiding something about this particular client or the therapeutic material, manifesting as a parapraxis (Freudian slip of action).", difficulty: 3, category: "Psychodynamic Therapy", topic: "Countertransference" },
  { id: "rp-804", stem: "Klein's 'depressive position' represents a developmental achievement because the infant:", options: ["Integrates good and bad aspects of the object and experiences guilt about destructive fantasies","Learns to repress all aggressive impulses","Develops the capacity for paranoid thinking","Achieves complete independence from the caregiver"], correctIndex: 0, rationale: "The depressive position (Klein) marks the infant's capacity to perceive the mother as a whole object containing both good and bad qualities. This integration brings guilt about prior destructive fantasies and concern for the object, enabling reparation.", difficulty: 4, category: "Psychodynamic Therapy", topic: "Object Relations" },
  { id: "rp-805", stem: "A client who cannot recall any memories from ages 3 to 7, a period during which family records indicate significant abuse occurred, is likely experiencing:", options: ["Repression of traumatic memories","Normal childhood amnesia","Fabrication of abuse history","Neurological memory impairment"], correctIndex: 0, rationale: "While some childhood amnesia is normative for very early years, the selective absence of memories during a period of documented abuse suggests repression - the unconscious exclusion of painful experiences from awareness as a protective mechanism.", difficulty: 2, category: "Psychodynamic Therapy", topic: "Defense Mechanisms" },
  { id: "rp-806", stem: "In short-term psychodynamic therapy (e.g., Davanloo's ISTDP), the therapist actively addresses resistance by:", options: ["Challenging defenses and pressing for the experience of warded-off feelings","Remaining completely silent until the client leads","Avoiding all confrontation to maintain the alliance","Focusing exclusively on cognitive restructuring"], correctIndex: 0, rationale: "ISTDP (Intensive Short-Term Dynamic Psychotherapy) uses active techniques to identify and challenge defenses, mobilize unconscious anxiety, and facilitate the direct experience of warded-off feelings, accelerating the therapeutic process.", difficulty: 4, category: "Psychodynamic Therapy", topic: "Psychoanalytic Concepts" },
  { id: "rp-807", stem: "A young professional whose surgeon father was emotionally distant pursues medicine and becomes highly skilled but remains unable to form intimate relationships. This pattern most likely involves:", options: ["Identification with the aggressor combined with repetition of the relational pattern","A conscious and healthy career choice","Sublimation alone without relational implications","Reaction formation against medical ambitions"], correctIndex: 0, rationale: "Identification with the aggressor (A. Freud) involves internalizing qualities of a threatening figure. The client identifies with the distant surgeon father professionally but also repeats the emotional unavailability pattern relationally.", difficulty: 4, category: "Psychodynamic Therapy", topic: "Defense Mechanisms" },
  { id: "rp-808", stem: "The concept of 'evenly suspended attention' (Freud) instructs the analyst to:", options: ["Listen without privileging any particular element of the patient's communication","Focus intensely on the most emotionally charged material","Take detailed notes during the session","Maintain constant eye contact with the patient"], correctIndex: 0, rationale: "Evenly suspended attention (gleichschwebende Aufmerksamkeit) is Freud's recommendation that the analyst listen without directing attention to any specific content, allowing unconscious patterns and themes to emerge naturally.", difficulty: 3, category: "Psychodynamic Therapy", topic: "Psychoanalytic Concepts" },
  { id: "rp-809", stem: "A client says their domineering boss is 'just like my father' and begins responding submissively to any suggestion the therapist makes. The therapist should:", options: ["Interpret the transference by exploring the connection between the boss, father, and therapeutic relationship","Agree with the client's perception without further exploration","Become more directive to meet the client's expectations","Refer the client for career counseling"], correctIndex: 0, rationale: "The client is demonstrating transference by generalizing the submissive pattern from father to boss to therapist. Psychodynamic interpretation helps the client become aware of how early relational patterns are repeated across relationships.", difficulty: 3, category: "Psychodynamic Therapy", topic: "Transference" },
  { id: "rp-810", stem: "In attachment theory, 'earned security' refers to:", options: ["Adults who had insecure childhoods but developed secure attachment through later relationships or therapy","Children who earn privileges through secure behavior","Security achieved through financial stability","Attachment patterns that are genetically determined"], correctIndex: 0, rationale: "Earned security describes adults who, despite insecure childhood attachment experiences, have developed coherent narratives about their past and demonstrate secure attachment in current relationships, often through reflective processing or therapy.", difficulty: 3, category: "Psychodynamic Therapy", topic: "Attachment Theory" },
  { id: "rp-811", stem: "A client who describes their childhood as 'perfectly fine' but cannot provide specific memories and dismisses emotions is showing features of:", options: ["Dismissive-avoidant attachment as measured by the Adult Attachment Interview","Secure attachment with well-integrated memories","Anxious-preoccupied attachment","Histrionic personality style"], correctIndex: 0, rationale: "On the AAI, dismissing adults idealize or normalize childhood while lacking specific supporting memories. They minimize the impact of early relationships and show restricted affect when discussing attachment-related topics.", difficulty: 4, category: "Psychodynamic Therapy", topic: "Attachment Theory" },
  { id: "rp-812", stem: "The defense mechanism of 'denial' differs from 'repression' in that denial:", options: ["Involves refusing to acknowledge an external reality, while repression keeps internal impulses from awareness","Is always a conscious process","Is considered a healthier defense mechanism","Only occurs in psychotic disorders"], correctIndex: 0, rationale: "Denial operates on external reality (refusing to acknowledge a painful fact), while repression operates on internal psychological content (keeping unacceptable wishes and memories from consciousness). Both are unconscious processes.", difficulty: 2, category: "Psychodynamic Therapy", topic: "Defense Mechanisms" },
  { id: "rp-813", stem: "Kohut's concept of 'idealizing transference' in self psychology involves the client:", options: ["Seeking to merge with an idealized powerful other to maintain self-cohesion","Projecting negative qualities onto the therapist","Developing realistic admiration for the therapist's skills","Competing with the therapist for superiority"], correctIndex: 0, rationale: "In idealizing transference, the client needs to experience the therapist as a calm, powerful, wise figure with whom they can merge. This reflects the unmet developmental need for an idealized parental imago (selfobject function).", difficulty: 4, category: "Psychodynamic Therapy", topic: "Transference" },
  { id: "rp-814", stem: "A therapist working with a client who uses extensive intellectualization should:", options: ["Gently redirect attention to the emotional experience underlying the intellectual content","Engage in extensive intellectual discussion to build rapport","Confront the defense aggressively to break through it quickly","Accept the intellectualization as the client's preferred communication style without intervention"], correctIndex: 0, rationale: "The therapist helps the client connect intellectual content with the warded-off emotions by gently drawing attention to the discrepancy between the content being discussed and the absence of emotional engagement.", difficulty: 2, category: "Psychodynamic Therapy", topic: "Defense Mechanisms" },
  { id: "rp-815", stem: "In object relations therapy, 'part-object relating' refers to:", options: ["Experiencing others as fulfilling only specific functions rather than as whole persons with complex qualities","Relating to only part of the therapy session","Having a partial understanding of the treatment plan","The therapist focusing on only one aspect of the client's presentation"], correctIndex: 0, rationale: "Part-object relating involves perceiving others in terms of the functions they serve (e.g., the gratifying breast) rather than as complete persons. It is characteristic of primitive psychological organization and the paranoid-schizoid position.", difficulty: 4, category: "Psychodynamic Therapy", topic: "Object Relations" },
  { id: "rp-816", stem: "Freud's concept of 'parapraxis' (Freudian slip) suggests that:", options: ["Everyday errors in speech, memory, and action reveal unconscious wishes and conflicts","All errors are random and psychologically meaningless","Only major errors carry psychological significance","Slips of the tongue are always sexual in nature"], correctIndex: 0, rationale: "Freud proposed that seemingly accidental errors (slips of the tongue, forgetting names, misreadings) are meaningful expressions of unconscious intentions, wishes, or conflicts that break through the ego's defenses.", difficulty: 2, category: "Psychodynamic Therapy", topic: "Psychoanalytic Concepts" },
  { id: "rp-817", stem: "A client who was the parentified child in their family of origin now struggles with boundaries in therapy, frequently bringing gifts and trying to take care of the therapist. This reflects:", options: ["Transference based on internalized caretaking role from childhood","Appropriate therapeutic generosity","Cultural norms around gift-giving","Evidence of secure attachment"], correctIndex: 0, rationale: "The parentified child developed a relational template where their value depends on caretaking others. This pattern transfers to therapy, where the client unconsciously attempts to replicate the familiar role that earned them conditional acceptance.", difficulty: 3, category: "Psychodynamic Therapy", topic: "Transference" },
  { id: "rp-818", stem: "According to Anna Freud, the defense mechanisms can be arranged along a developmental hierarchy from primitive to mature. Which of the following is considered most primitive?", options: ["Splitting","Humor","Suppression","Altruism"], correctIndex: 0, rationale: "Splitting is among the most primitive defenses, emerging in early infancy to manage overwhelming affect by dividing experience into all-good and all-bad categories. Humor, suppression, and altruism are mature defenses requiring advanced ego development.", difficulty: 2, category: "Psychodynamic Therapy", topic: "Defense Mechanisms" },
  { id: "rp-819", stem: "In psychodynamic formulation, the concept of 'core conflictual relationship theme' (CCRT) by Luborsky identifies:", options: ["Recurring patterns of wishes, expected responses from others, and responses of self across relationships","The single most important trauma in the client's history","The therapist's interpretation of the client's primary diagnosis","A behavioral pattern observable only in the therapeutic relationship"], correctIndex: 0, rationale: "Luborsky's CCRT method identifies recurring relationship patterns across narratives by examining three components: the client's wish (W), the expected or actual response from others (RO), and the client's response to that (RS).", difficulty: 5, category: "Psychodynamic Therapy", topic: "Psychoanalytic Concepts" },
  { id: "rp-820", stem: "A client who experienced early neglect demonstrates a 'compulsion to repeat' (Freud) by:", options: ["Unconsciously recreating situations of neglect in current relationships despite conscious wishes for different outcomes","Deliberately choosing neglectful partners","Consciously repeating positive relationship patterns","Repeating verbal affirmations in session"], correctIndex: 0, rationale: "The repetition compulsion drives the individual to unconsciously recreate early traumatic relational scenarios. Despite consciously wanting different outcomes, the pull of the familiar pattern and the wish to master the original trauma perpetuate the cycle.", difficulty: 3, category: "Psychodynamic Therapy", topic: "Psychoanalytic Concepts" },
  { id: "rp-821", stem: "Main and Hesse's concept of 'disorganized attachment' is most associated with caregiving that is:", options: ["Frightening or frightened, placing the child in an irresolvable paradox","Consistently warm and responsive","Predictably cold and rejecting","Overly indulgent and boundary-less"], correctIndex: 0, rationale: "Disorganized attachment (Type D) results when the caregiver is simultaneously the source of comfort and fear (frightening/frightened behavior). The child faces an irresolvable paradox: the haven of safety is also the source of threat.", difficulty: 3, category: "Psychodynamic Therapy", topic: "Attachment Theory" },
  { id: "rp-822", stem: "A client who volunteers excessive personal details about their childhood without emotional affect in early sessions may be demonstrating:", options: ["Pseudo-compliance as a defense against genuine therapeutic engagement","Readiness for deep psychodynamic work","Excellent therapeutic motivation","Histrionic personality traits"], correctIndex: 0, rationale: "Excessive early disclosure without affect suggests a defensive operation where the appearance of openness substitutes for genuine engagement. The client may be unconsciously preempting the therapist's exploration by offering content stripped of emotional significance.", difficulty: 4, category: "Psychodynamic Therapy", topic: "Defense Mechanisms" },
  { id: "rp-823", stem: "Sullivan's interpersonal theory emphasizes that personality is:", options: ["Primarily shaped by and expressed through interpersonal relationships","An innate, biologically determined structure","Formed exclusively during the first year of life","Independent of social context"], correctIndex: 0, rationale: "Sullivan proposed that personality cannot exist apart from interpersonal relationships. He defined psychiatry as the study of interpersonal relations and argued that the self-system develops through reflected appraisals from significant others.", difficulty: 3, category: "Psychodynamic Therapy", topic: "Psychoanalytic Concepts" },
  { id: "rp-824", stem: "When a psychodynamic therapist makes a 'mutative interpretation,' they are:", options: ["Offering an interpretation within the transference that creates immediate emotional impact and promotes insight","Suggesting the client change their behavior","Interpreting a dream using symbolic analysis","Making a genetic interpretation about childhood events"], correctIndex: 0, rationale: "Strachey defined the mutative interpretation as one that interprets the here-and-now transference, creating an immediate emotional experience that contrasts the archaic fantasy with present reality, leading to structural psychic change.", difficulty: 5, category: "Psychodynamic Therapy", topic: "Psychoanalytic Concepts" },
  { id: "rp-825", stem: "A client under stress at work begins cracking jokes and making humorous observations about their distressing situation in session. This represents:", options: ["Humor as a mature defense mechanism","Avoidance requiring immediate confrontation","Evidence of hypomania","Inappropriate affect suggesting thought disorder"], correctIndex: 0, rationale: "Humor is classified as a mature defense mechanism that allows acknowledgment of the distressing reality while creating emotional distance through comedic framing. It differs from manic defense in that reality is not denied.", difficulty: 1, category: "Psychodynamic Therapy", topic: "Defense Mechanisms" },
  { id: "rp-826", stem: "In Bowlby's theory, the 'protest-despair-detachment' sequence describes:", options: ["The stages of response to prolonged separation from the attachment figure","The developmental stages of normal attachment","The phases of psychoanalytic treatment","Stages of grief in bereavement"], correctIndex: 0, rationale: "Bowlby observed that young children separated from attachment figures progress through protest (crying, searching), despair (withdrawal, mourning), and detachment (apparent indifference that masks defensive exclusion of attachment needs).", difficulty: 3, category: "Psychodynamic Therapy", topic: "Attachment Theory" },
  { id: "rp-827", stem: "A therapist who consistently interprets material before the client is emotionally ready may be enacting:", options: ["Countertransference through premature interpretation driven by the therapist's own anxiety","Optimal psychoanalytic technique","Evidence-based practice","Appropriate therapeutic confrontation"], correctIndex: 0, rationale: "Premature interpretation often reflects the therapist's countertransferential need to demonstrate understanding, manage their own anxiety about not-knowing, or maintain intellectual control. It bypasses the client's natural process of discovery.", difficulty: 3, category: "Psychodynamic Therapy", topic: "Countertransference" },
  { id: "rp-828", stem: "The defense mechanism of 'somatization' involves:", options: ["Converting psychological distress into physical complaints","Redirecting aggression toward a less threatening target","Attributing one's own feelings to others","Regressing to an earlier developmental stage"], correctIndex: 0, rationale: "Somatization transforms emotional distress into bodily symptoms. The psychological conflict is expressed through the body, and the individual may be completely unaware of the emotional origins of their physical complaints.", difficulty: 1, category: "Psychodynamic Therapy", topic: "Defense Mechanisms" },
  { id: "rp-829", stem: "In contemporary relational psychoanalysis, 'enactments' are understood as:", options: ["Mutual, co-created interactions where unconscious dynamics of both therapist and client are expressed through action rather than words","Conscious role-plays used for skill-building","Deliberate therapeutic provocations","Client behaviors that require behavioral intervention"], correctIndex: 0, rationale: "Relational analysts view enactments as inevitable interpersonal events where both participants' unconscious processes interact. They provide crucial clinical material when recognized and processed, revealing the relational dynamics being replicated.", difficulty: 5, category: "Psychodynamic Therapy", topic: "Psychoanalytic Concepts" },
  { id: "rp-830", stem: "A client who was severely punished for expressing anger as a child now experiences chronic depression. Psychodynamic theory would suggest the depression may involve:", options: ["Anger turned inward against the self","Excessive serotonin production","Inadequate behavioral reinforcement","Cognitive distortions about future events"], correctIndex: 0, rationale: "Classical psychoanalytic theory (Abraham, Freud) conceptualizes depression as aggression retroflected against the self. When outward expression of anger was punished, the individual turns hostile impulses inward, resulting in self-punishment and depressive affect.", difficulty: 2, category: "Psychodynamic Therapy", topic: "Psychoanalytic Concepts" },
  { id: "rp-831", stem: "Winnicott's concept of 'potential space' in therapy refers to:", options: ["An intermediate area of experience between inner reality and external life where creativity and play can occur","The physical space between therapist and client chairs","The therapist's waiting room","Time between sessions"], correctIndex: 0, rationale: "Potential space is the transitional area between subjectivity and objectivity where creative living, play, and cultural experience occur. In therapy, it is the collaborative space where new meanings and experiences can emerge.", difficulty: 4, category: "Psychodynamic Therapy", topic: "Object Relations" },
  { id: "rp-832", stem: "A client exhibits 'as-if' personality functioning, adapting their presentation dramatically depending on who they are with. This was described by:", options: ["Deutsch, as a form of identity disturbance related to lack of genuine self-development","Rogers, as a sign of therapeutic progress","Kohut, as healthy narcissistic functioning","Bowlby, as secure attachment flexibility"], correctIndex: 0, rationale: "Helene Deutsch described 'as-if' personalities who lack genuine emotional depth and adopt the qualities of those around them. This chameleon-like functioning reflects impoverished internalization and absence of a cohesive authentic self.", difficulty: 5, category: "Psychodynamic Therapy", topic: "Object Relations" },
  { id: "rp-833", stem: "The defense mechanism of 'acting out' differs from 'acting in' in that acting out:", options: ["Involves expressing unconscious conflicts through behavior outside the therapy setting","Occurs exclusively within the therapeutic relationship","Is always a conscious and deliberate process","Represents a mature coping strategy"], correctIndex: 0, rationale: "Acting out expresses unconscious material through action in the external world rather than through verbal communication in therapy. 'Acting in' refers to similar behavioral expression occurring within the therapy session itself.", difficulty: 3, category: "Psychodynamic Therapy", topic: "Defense Mechanisms" },
  { id: "rp-834", stem: "A therapist using Scharff and Scharff's object relations approach to couples therapy focuses primarily on:", options: ["How each partner's internal object world interacts with and is projected onto the other","Teaching communication skills and conflict resolution techniques","Restructuring the couple's behavioral patterns through reinforcement","Assigning homework to improve intimacy"], correctIndex: 0, rationale: "Object relations couples therapy (Scharff & Scharff) examines how each partner's internalized object relations are projected onto and enacted with the other, creating interlocking pathological systems that replicate early relational patterns.", difficulty: 5, category: "Psychodynamic Therapy", topic: "Object Relations" },
  { id: "rp-835", stem: "A client presents with alexithymia, which is characterized by:", options: ["Difficulty identifying and describing one's own emotional states","Excessive emotional reactivity","Inability to form any interpersonal relationships","Persistent auditory hallucinations"], correctIndex: 0, rationale: "Alexithymia involves difficulty identifying, describing, and distinguishing feelings from bodily sensations. It is associated with psychosomatic disorders and is understood psychodynamically as reflecting inadequate early affect mirroring and mentalization development.", difficulty: 2, category: "Psychodynamic Therapy", topic: "Psychoanalytic Concepts" },
  { id: "rp-836", stem: "In Kohut's self psychology, a 'selfobject' is best defined as:", options: ["An object experienced as part of the self that provides essential psychological functions for maintaining self-cohesion","The client's sense of their own identity","A transitional object like a blanket or teddy bear","An imaginary friend"], correctIndex: 0, rationale: "Selfobjects are not separate objects but are experienced as extensions of the self. They provide mirroring (validation), idealizing (sense of being connected to something powerful), and twinship (sense of essential alikeness) functions.", difficulty: 3, category: "Psychodynamic Therapy", topic: "Object Relations" },
  { id: "rp-837", stem: "A client who unconsciously adopts the values and behaviors of a feared authority figure is using the defense of:", options: ["Identification with the aggressor","Introjection","Projection","Displacement"], correctIndex: 0, rationale: "Identification with the aggressor (Anna Freud) involves unconsciously taking on the qualities of a threatening person to manage anxiety. By becoming like the feared figure, the individual transforms from helpless victim to active agent.", difficulty: 2, category: "Psychodynamic Therapy", topic: "Defense Mechanisms" },
  { id: "rp-838", stem: "The Adult Attachment Interview (AAI) primarily assesses:", options: ["The coherence and organization of the individual's narrative about their childhood attachment experiences","Current romantic relationship satisfaction","Attachment behaviors in the therapy session","Diagnostic criteria for attachment disorders"], correctIndex: 0, rationale: "The AAI (George, Kaplan, Main) is a semi-structured interview assessing the quality of adults' attachment representations through the coherence of their narrative about childhood experiences, not the content of what happened.", difficulty: 3, category: "Psychodynamic Therapy", topic: "Attachment Theory" },
  { id: "rp-839", stem: "A client who transforms their childhood experience of abuse into a career as a child protection advocate is demonstrating:", options: ["Sublimation of traumatic experience into prosocial activity","Denial of the abuse","Reaction formation against abusive impulses","Regression to a caretaking role"], correctIndex: 0, rationale: "Sublimation channels the energy from painful experiences into constructive, socially valued activities. The client transforms suffering into advocacy, partially gratifying the wish to protect while contributing meaningfully to society.", difficulty: 1, category: "Psychodynamic Therapy", topic: "Defense Mechanisms" },
  { id: "rp-840", stem: "In psychodynamic therapy, 'therapeutic neutrality' means:", options: ["Maintaining equidistance between id, ego, and superego without taking sides in the client's internal conflicts","Being emotionally cold and distant","Refusing to express any opinion","Not caring about the client's outcome"], correctIndex: 0, rationale: "Therapeutic neutrality (Anna Freud) means the analyst does not align with any one psychic agency (id impulses, ego defenses, or superego prohibitions) but maintains equidistance, allowing all aspects to emerge for exploration.", difficulty: 3, category: "Psychodynamic Therapy", topic: "Psychoanalytic Concepts" },
  { id: "rp-841", stem: "A client who experienced insecure attachment begins to develop trust in the therapist after two years of consistent sessions. This process in psychodynamic therapy is called:", options: ["Development of a new relational experience that modifies internal working models","Symptom substitution","Resistance resolution","Termination readiness"], correctIndex: 0, rationale: "Long-term consistent therapeutic relationships can modify internal working models by providing new relational experiences that disconfirm expectations based on early insecure attachment. This is a core mechanism of change in attachment-informed psychotherapy.", difficulty: 2, category: "Psychodynamic Therapy", topic: "Attachment Theory" },
  { id: "rp-842", stem: "In object relations theory, 'introjection' is the process by which:", options: ["External objects and their qualities are taken into the internal world and become part of the self","Internal objects are expelled into the external world","The ego splits into good and bad parts","The child learns to imitate others through observation"], correctIndex: 0, rationale: "Introjection is the process of incorporating external objects (or their qualities) into one's internal world. The introject becomes an internal presence that shapes self-experience, for better or worse (e.g., a critical introject from a harsh parent).", difficulty: 3, category: "Psychodynamic Therapy", topic: "Object Relations" },
  { id: "rp-843", stem: "A therapist realizes mid-session that they have been unusually harsh in their interpretations of a particular client. This awareness most likely reflects:", options: ["Recognition of a concordant or complementary countertransference enactment","A deliberate therapeutic confrontation strategy","Normal variation in clinical style","The client's improved tolerance for direct feedback"], correctIndex: 0, rationale: "Racker distinguished concordant countertransference (identifying with the client's emotional state) from complementary countertransference (identifying with the client's internal objects). Unusual harshness suggests the therapist is enacting a complementary identification with a punitive internal object.", difficulty: 5, category: "Psychodynamic Therapy", topic: "Countertransference" },
  { id: "rp-844", stem: "Freud's 'Oedipus complex' describes:", options: ["The child's unconscious sexual desire for the opposite-sex parent and rivalry with the same-sex parent","A fear of enclosed spaces","The infant's oral fixation","The adolescent's identity crisis"], correctIndex: 0, rationale: "The Oedipus complex (typically ages 3-6) involves the child's desire for exclusive possession of the opposite-sex parent and competitive rivalry with the same-sex parent. Its resolution through identification contributes to superego formation.", difficulty: 1, category: "Psychodynamic Therapy", topic: "Psychoanalytic Concepts" },
  { id: "rp-845", stem: "A client who idealizes their deceased mother and cannot recall any negative experiences with her may be using:", options: ["Idealization as a defense against ambivalent feelings toward the lost object","Accurate memory retrieval","Healthy grief processing","Denial of the mother's death"], correctIndex: 0, rationale: "Idealization of the deceased protects against painful ambivalent feelings (love mixed with anger, disappointment). In pathological grief, the inability to access negative memories prevents working through the loss and integrating the whole-object representation.", difficulty: 3, category: "Psychodynamic Therapy", topic: "Defense Mechanisms" },
  { id: "rp-846", stem: "In attachment-based psychotherapy, 'mentalization-based treatment' (MBT) was developed primarily for:", options: ["Borderline personality disorder, focusing on strengthening the capacity to understand mental states","Specific phobias, using exposure techniques","Autism spectrum disorder, teaching social skills","Substance use disorders, using motivational techniques"], correctIndex: 0, rationale: "MBT (Bateman & Fonagy) was developed for BPD, targeting the characteristic mentalization failures. Treatment focuses on strengthening the patient's capacity to understand behavior in terms of underlying mental states, particularly in the context of attachment relationships.", difficulty: 3, category: "Psychodynamic Therapy", topic: "Attachment Theory" },
  { id: "rp-847", stem: "The defense mechanism of 'dissociation' in psychodynamic theory involves:", options: ["A disruption in the normally integrated functions of consciousness, memory, identity, or perception","A deliberate attempt to forget unpleasant experiences","The separation of emotion from intellectual content only","Projection of unwanted parts onto others"], correctIndex: 0, rationale: "Dissociation represents a more severe defensive process where aspects of experience are segregated from conscious awareness. It ranges from mild detachment to severe fragmentation and is commonly associated with trauma.", difficulty: 2, category: "Psychodynamic Therapy", topic: "Defense Mechanisms" },
  { id: "rp-848", stem: "A psychodynamic therapist who attends to their own 'reverie' (Bion) during sessions is using:", options: ["Their own unconscious mental processes as a source of information about the client's internal world","Daydreaming as a relaxation technique","A cognitive-behavioral attention-training strategy","Conscious problem-solving methods"], correctIndex: 0, rationale: "Bion encouraged analysts to attend to their reverie (daydreams, images, associations) during sessions as potential communications from the patient's unconscious processed through the analyst's containing function. This parallels the mother's processing of the infant's projections.", difficulty: 5, category: "Psychodynamic Therapy", topic: "Psychoanalytic Concepts" },
  { id: "rp-849", stem: "A client diagnosed with narcissistic personality disorder experiences a 'narcissistic injury' when:", options: ["Their grandiose self-image is challenged or contradicted by reality, leading to rage or shame","They receive genuine praise and recognition","They successfully achieve a professional goal","They form a healthy intimate relationship"], correctIndex: 0, rationale: "Narcissistic injury occurs when the individual's inflated self-image is threatened by criticism, failure, or perceived slight. This triggers disproportionate reactions of narcissistic rage, withdrawal, or shame due to the fragility of the grandiose self-structure.", difficulty: 2, category: "Psychodynamic Therapy", topic: "Object Relations" },
  { id: "rp-850", stem: "The concept of 'signal anxiety' (Freud, 1926 revision) describes:", options: ["The ego's anticipatory warning of danger that activates defense mechanisms before the full anxiety response develops","The physical symptoms accompanying panic attacks","Anxiety as a learned response to conditioned stimuli","Free-floating anxiety without identifiable cause"], correctIndex: 0, rationale: "In Freud's revised anxiety theory, signal anxiety is a small dose of anxiety generated by the ego as an early warning system when it detects a potential danger situation (loss of object, loss of love, castration, superego punishment), mobilizing defenses preemptively.", difficulty: 4, category: "Psychodynamic Therapy", topic: "Psychoanalytic Concepts" },
];
